import './Button.scss';

import React, { forwardRef } from 'react';

import { classNames } from '../../helpers/classnames';
import type { ButtonColorVariants, ButtonProps } from './Button.types';

const VARIANT_ALIAS_MAP: Partial<Record<ButtonColorVariants, ButtonColorVariants>> = {
	primary: 'contained',
	secondary: 'outlined',
	ghost: 'plain',
	inverse: 'overlay',
};

export function resolveVariant(variant: ButtonColorVariants): ButtonColorVariants {
	return VARIANT_ALIAS_MAP[variant] ?? variant;
}

export const Button = forwardRef<HTMLButtonElement | HTMLAnchorElement, ButtonProps>(
	(
		{
			className,
			children,
			size = 'small',
			variant = 'secondary',
			disabled,
			startIcon,
			endIcon,
			fullWidth = false,
			href,
			dataTestId = 'Button',
			...props
		},
		ref,
	) => {
		const resolvedVariant = resolveVariant(variant);

		const buttonClassNames = classNames(
			'dsb_button',
			`dsb_button__${size}`,
			`dsb_button__${resolvedVariant}`,
			{
				'dsb_button__start-icon': !!startIcon,
				'dsb_button__end-icon': !!endIcon,
				'dsb_button__icon-button': !children,
				dsb_button__disabled: disabled,
				'dsb_button__full-width': fullWidth,
				dsb_button__link: !!href,
			},
			className,
		);

		if (href) {
			return (
				<a {...props} href={href} className={buttonClassNames} ref={ref as React.Ref<HTMLAnchorElement>} role="button" data-testid={dataTestId}>
					{startIcon && (
						<div className="dsb_button-start-icon" aria-hidden="true">
							{startIcon}
						</div>
					)}
					{children}
					{endIcon && (
						<div className="dsb_button-end-icon" aria-hidden="true">
							{endIcon}
						</div>
					)}
				</a>
			);
		}
		return (
			<button
				data-testid={dataTestId}
				{...props}
				className={buttonClassNames}
				disabled={disabled}
				ref={ref as React.Ref<HTMLButtonElement>}
			>
				{startIcon && (
					<div className="dsb_button-start-icon" aria-hidden="true">
						{startIcon}
					</div>
				)}
				{children}
				{endIcon && (
					<div className="dsb_button-end-icon" aria-hidden="true">
						{endIcon}
					</div>
				)}
			</button>
		);
	},
);
